import React, { useState } from 'react';
import { View, Button, Alert } from 'react-native';
import InAppPurchase from 'react-native-iap';
import { useEffect } from 'react';

const PaymentModule = () => {
  const [products, setProducts] = useState([]);
  const [isInitialized, setIsInitialized] = useState(false);

  useEffect(() => {
    const initPayment = async () => {
      try {
        await InAppPurchase.initConnection();
        const productIds = ['product1', 'product2']; // Replace with your product IDs
        const availableProducts = await InAppPurchase.getProducts(productIds);
        setProducts(availableProducts);
        setIsInitialized(true);
      } catch (error) {
        console.error('Payment initialization error:', error);
      }
    };

    initPayment();

    return () => {
      InAppPurchase.endConnection();
    };
  }, []);

  const handlePurchase = async (productId) => {
    try {
      const purchase = await InAppPurchase.requestPurchase(productId);
      // Handle purchase verification and processing here
      Alert.alert('Purchase Successful', `You have purchased ${productId}`);
    } catch (error) {
      console.error('Purchase error:', error);
      Alert.alert('Purchase Failed', 'Please try again later.');
    }
  };

  return (
    <View>
      {isInitialized && products.map((product) => (
        <Button
          key={product.productId}
          title={`Buy ${product.title}`}
          onPress={() => handlePurchase(product.productId)}
        />
      ))}
    </View>
  );
};

export default PaymentModule;